// main.dart
import 'package:flutter/material.dart';
import 'package:flutter_dotenv/flutter_dotenv.dart';
import 'package:image_picker/image_picker.dart';
import 'package:minio/minio.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';
import 'dart:io';

Future<void> main() async {
  await dotenv.load(fileName: ".env");
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Photo Analyzer',
      theme: ThemeData(primarySwatch: Colors.blue),
      home: PhotoUploadScreen(),
    );
  }
}

class PhotoUploadScreen extends StatefulWidget {
  @override
  _PhotoUploadScreenState createState() => _PhotoUploadScreenState();
}

class _PhotoUploadScreenState extends State<PhotoUploadScreen> {
  final ImagePicker _picker = ImagePicker();
  File? _selectedImage;
  String _analysisResult = '';
  bool _isLoading = false;

  late Minio _s3Client;

  @override
  void initState() {
    super.initState();
    _initializeS3();
  }

  void _initializeS3() {
    _s3Client = Minio(
      endPoint: 's3.amazonaws.com',
      accessKey: dotenv.env['AWS_ACCESS_KEY']!,
      secretKey: dotenv.env['AWS_SECRET_KEY']!,
    );
  }

  Future<void> _pickImage() async {
    final XFile? image = await _picker.pickImage(source: ImageSource.gallery);
    if (image != null) {
      setState(() {
        _selectedImage = File(image.path);
        _analysisResult = '';
      });
    }
  }

  Future<void> _uploadAndAnalyze() async {
    if (_selectedImage == null) return;

    setState(() {
      _isLoading = true;
    });

    try {
      String bucketName = dotenv.env['S3_BUCKET']!;
      String fileName = 'uploads/${DateTime.now().millisecondsSinceEpoch}.jpg';

      await _s3Client.fPutObject(bucketName, fileName, _selectedImage!.path);

      await _analyzeImage(_selectedImage!);

      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Upload successful!')),
      );
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error: $e')),
      );
    } finally {
      setState(() {
        _isLoading = false;
      });
    }
  }

  Future<void> _analyzeImage(File image) async {
    String apiKey = dotenv.env['GOOGLE_CLOUD_API_KEY']!;
    String url = 'https://vision.googleapis.com/v1/images:annotate?key=$apiKey';

    List<int> imageBytes = await image.readAsBytes();
    String base64Image = base64Encode(imageBytes);

    var response = await http.post(
      Uri.parse(url),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'requests': [
          {
            'image': {'content': base64Image},
            'features': [
              {'type': 'LABEL_DETECTION', 'maxResults': 10},
              {'type': 'TEXT_DETECTION'},
            ]
          }
        ]
      }),
    );

    if (response.statusCode == 200) {
      var data = jsonDecode(response.body);
      setState(() {
        _analysisResult = _formatAnalysis(data);
      });
    }
  }

  String _formatAnalysis(Map<String, dynamic> data) {
    StringBuffer result = StringBuffer();
    var responses = data['responses'][0];

    if (responses.containsKey('labelAnnotations')) {
      result.writeln('Labels:');
      for (var label in responses['labelAnnotations']) {
        result.writeln('- ${label['description']} (${(label['score'] * 100).toStringAsFixed(1)}%)');
      }
    }

    if (responses.containsKey('textAnnotations')) {
      result.writeln('\nDetected Text:');
      result.writeln(responses['textAnnotations'][0]['description']);
    }

    return result.toString();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Photo Analyzer')),
      body: SingleChildScrollView(
        padding: EdgeInsets.all(16),
        child: Column(
          children: [
            if (_selectedImage != null)
              Image.file(_selectedImage!, height: 300),
            SizedBox(height: 20),
            ElevatedButton.icon(
              onPressed: _pickImage,
              icon: Icon(Icons.photo_library),
              label: Text('Select Photo'),
            ),
            SizedBox(height: 10),
            ElevatedButton.icon(
              onPressed: _isLoading ? null : _uploadAndAnalyze,
              icon: Icon(Icons.cloud_upload),
              label: Text('Upload & Analyze'),
            ),
            if (_isLoading) CircularProgressIndicator(),
            SizedBox(height: 20),
            if (_analysisResult.isNotEmpty)
              Card(
                child: Padding(
                  padding: EdgeInsets.all(16),
                  child: Text(_analysisResult),
                ),
              ),
          ],
        ),
      ),
    );
  }
}